INSERT INTO `tbl_auto_mail_skin` VALUES (3,'문의답변','&lt;div id=&#34mailing_wrap&#34 style=&#34margin: 0px auto; border: 20px solid rgb(242, 242, 242); border-image: none; width: 770px; box-sizing: border-box; background-color: rgb(242, 242, 242);&#34&gt;\r\n		&lt;header style=&#34height: 126px; overflow: hidden; border-bottom-color: rgb(204, 204, 204); border-bottom-width: 1px; border-bottom-style: solid; background-color: rgb(255, 255, 255);&#34&gt;\r\n			&lt;h1 style=&#34margin: 0px; padding: 0px;&#34&gt;&lt;a style=&#34margin: 0px; padding: 0px;&#34 href=&#34[http_domain_url]&#34&gt;&lt;img style=&#34margin: 30px; line-height: 126px; vertical-align: middle; float: left;&#34 alt=&#34&#34 src=&#34[logos]&#34&gt;&lt;/a&gt;&lt;/h1&gt;\r\n			&lt;h2 style=&#34margin: 0px 30px 0px 0px; padding: 0px; color: rgb(51, 51, 51); line-height: 126px; font-size: 24px; font-weight: 400; float: right;&#34&gt;문의답변메일&lt;/h2&gt;\r\n		&lt;/header&gt;\r\n		&lt;section class=&#34mailing_container&#34 style=&#34padding: 90px 40px 70px; text-align: left; box-sizing: border-box; background-color: rgb(255, 255, 255);&#34&gt;\r\n			&lt;p style=&#34margin: 0px; padding: 0px; line-height: 24px; font-size: 13px;&#34&gt;안녕하세요. &lt;span style=&#34font-weight: bold;&#34&gt;{{receive_name}}&lt;/span&gt; 고객님!&lt;/p&gt;\r\n			&lt;p style=&#34margin: 0px; padding: 0px; line-height: 24px; font-size: 13px;&#34&gt;저희 쇼핑몰을 이용해주셔서 진심으로 감사드립니다.&lt;/p&gt;\r\n			&lt;p style=&#34margin: 10px 0px 0px; padding: 0px; line-height: 24px; font-size: 13px; font-weight: bold;&#34&gt;[site_name]에 문의하신 내용 답변 드립니다.&lt;/p&gt;			\r\n\r\n			&lt;div&gt;\r\n				&lt;h3 style=&#34margin: 50px 0px 10px; font-size: 16px; font-weight: 600;&#34&gt;문의내용&lt;/h3&gt;\r\n				&lt;table class=&#34__se_tbl_ext&#34 style=&#34width: 100%;&#34 &#34=&#34&#34 cellspacing=&#34Ŕ&#34 cellpadding=&#34Ŕ&#34&gt;\r\n					&lt;tbody style=&#34border-top-color: rgb(136, 136, 136); border-top-width: 2px; border-top-style: solid;&#34&gt;\r\n						&lt;tr style=&#34width: 100%; line-height: 50px; font-size: 13px; border-bottom-color: rgb(220, 220, 220); border-bottom-width: 1px; border-bottom-style: solid; display: block; min-height: 50px;&#34&gt;\r\n							&lt;th style=&#34padding: 0px 0px 0px 20px; width: 140px; box-sizing: border-box; background-color: rgb(250, 250, 250);&#34&gt;날짜&lt;/th&gt;\r\n							&lt;td style=&#34padding: 0px 0px 0px 20px; font-weight: 700;&#34&gt;[date]&lt;/td&gt;\r\n						&lt;/tr&gt;\r\n						&lt;tr style=&#34width: 100%; line-height: 50px; font-size: 13px; border-bottom-color: rgb(220, 220, 220); border-bottom-width: 1px; border-bottom-style: solid; display: block; min-height: 50px;&#34&gt;\r\n							&lt;th style=&#34padding: 0px 0px 0px 20px; width: 140px; height: 100px; box-sizing: border-box; background-color: rgb(250, 250, 250);&#34&gt;내용&lt;/th&gt;\r\n							&lt;td style=&#34padding: 0px 0px 0px 20px; font-weight: 700;&#34&gt;[contents]&lt;/td&gt;\r\n						&lt;/tr&gt;\r\n					&lt;/tbody&gt;\r\n				&lt;/table&gt;	\r\n			&lt;/div&gt;\r\n			&lt;div&gt;\r\n				&lt;h3 style=&#34margin: 50px 0px 10px; font-size: 16px; font-weight: 600;&#34&gt;답변&lt;/h3&gt;\r\n				&lt;table class=&#34__se_tbl_ext&#34 style=&#34width: 100%;&#34 &#34=&#34&#34 cellspacing=&#34Ŕ&#34 cellpadding=&#34Ŕ&#34&gt;\r\n					&lt;tbody style=&#34border-top-color: rgb(136, 136, 136); border-top-width: 2px; border-top-style: solid;&#34&gt;\r\n						&lt;tr style=&#34width: 100%; line-height: 50px; font-size: 13px; border-bottom-color: rgb(220, 220, 220); border-bottom-width: 1px; border-bottom-style: solid; display: block; min-height: 50px;&#34&gt;\r\n							&lt;th style=&#34padding: 0px 0px 0px 20px; width: 140px; height: 100px; box-sizing: border-box; background-color: rgb(250, 250, 250);&#34&gt;내용&lt;/th&gt;\r\n							&lt;td style=&#34padding: 0px 0px 0px 20px; font-weight: 700;&#34&gt;[reply]&lt;/td&gt;\r\n						&lt;/tr&gt;\r\n					&lt;/tbody&gt;\r\n				&lt;/table&gt;	\r\n			&lt;/div&gt;\r\n		&lt;/section&gt;\r\n		&lt;section class=&#34mailing_container2&#34 style=&#34margin: 30px 0px 0px; padding: 30px 0px 30px 43px; background-color: rgb(255, 255, 255);&#34&gt;\r\n			&lt;p style=&#34text-align: left; line-height: 22px; letter-spacing: -1px; font-size: 13px; font-weight: 300;&#34&gt;\r\n				본 메일은 발신전용 메일이며 문의에 대한 회신 처리되지 않습니다. 문의사항은 고객센터를 이용해주세요.&lt;br&gt;\r\n				회원이 아니신 경우나 메일 수신거부 회원이신데도 메일을 받으신다면 [admin_email] 으로 연락해 주세요.\r\n			&lt;/p&gt;\r\n		&lt;/section&gt;\r\n		&lt;div class=&#34mailing_footer&#34 id=&#34footer&#34 style=&#34margin-top: 40px;&#34&gt;\r\n			&lt;div class=&#34footer_bot&#34 style=&#34height: 120px; background-color: rgb(242, 242, 242);&#34&gt;\r\n				&lt;div class=&#34wrap_layout&#34 style=&#34padding: 0px 43px; width: 100%; box-sizing: border-box;&#34&gt;\r\n					&lt;div class=&#34f_content&#34 style=&#34float: left;&#34&gt;\r\n						&lt;address style=&#34line-height: 22px; display: block;&#34&gt;&lt;address style=&#34line-height: 22px;&#34&gt;&lt;address style=&#34line-height: 22px;&#34&gt;&lt;address style=&#34line-height: 22px;&#34&gt;&lt;font color=&#34#959595&#34&gt;&lt;span style=&#34letter-spacing: -0.5px; font-style: normal;&#34&gt;[home_name] | [addr1] [addr2] |  대표 [info_owner]            &lt;/span&gt;&lt;/font&gt;&lt;/address&gt;&lt;address style=&#34line-height: 22px;&#34&gt;&lt;font color=&#34#959595&#34&gt;&lt;span style=&#34letter-spacing: -0.5px; font-style: normal;&#34&gt;사업자등록번호 [comnum]  |   통신판매업신고  [mall_order]&lt;/span&gt;&lt;/font&gt;&lt;/address&gt;&lt;address style=&#34line-height: 22px;&#34&gt;&lt;font color=&#34#959595&#34&gt;&lt;span style=&#34letter-spacing: -0.5px; font-style: normal;&#34&gt;고객센터 [custom_phone] |  이메일 : [admin_email]&lt;/span&gt;&lt;/font&gt;&lt;/address&gt;&lt;address style=&#34line-height: 22px;&#34&gt;&lt;font color=&#34#959595&#34&gt;&lt;span style=&#34letter-spacing: -0.5px; font-style: normal;&#34&gt;&lt;br&gt;&lt;/span&gt;&lt;/font&gt;&lt;/address&gt;&lt;address style=&#34line-height: 22px;&#34&gt;&lt;font 