INSERT INTO `tbl_auto_sms_skin` VALUES (2,'주문완료(입금대기)','[에코페어] [{{BANK_INFO}}] 으로 {{TOTAL_PRICE}}원 입금해주시면 주문하신 상품을 발송해드립니다. 감사합니다.','S02','Y'),(3,'입금완료','[에코페어] {{ORDER_DATE}} 주문하신 상품({{ORDER_ID}}) 결제가 완료 되었습니다. 신속히 준비하여 발송하겠습니다. 감사합니다.','S03','Y'),(6,'배송준비안내','[에코페어]{{ORDER_NAME}}님의 상품이 준비중입니다.','S06','Y'),(7,'상품발송안내','[에코페어]{{ORDER_NAME}}님의 주문하신 상품이 발송 되었습니다. 1~2일후 배송 예정입니다.','S07','Y'),(8,'주문완료안내','[에코페어]{{ORDER_NAME}}님 결제가 성공적으로 완료 되었습니다. 감사합니다.','S08','Y'),(9,'주문취소문자','[에코페어]{{ORDER_NAME}}님의 {{ORDER_ID}}주문건이 취소처리 되었습니다.','S09','Y'),(11,'회원가입축하','[에코페어]{{MEMBER_NAME}}님 가입을 진심으로 축하드립니다. 쇼핑 적립금 {{JOIN_POINT}}원을 선물로 넣어드렸습니다.','S11','Y');
/*!40000 ALTER TABLE `tbl_auto_sms_skin` ENABLE KEYS */;
UNLOCK TABLES;

