INSERT INTO `tbl_education` VALUES (16,'2023년도 항내운항안전교육','CS','서울/부산',1,25,0,6,3,200000,'KP&I 300만원/월 지원','&lt;p&gt;교육개요&lt;/p&gt;&lt;p&gt;&lt;br&gt;&lt;/p&gt;&lt;p&gt;교육 목적 : 항내 선박 조종 이론 습득 및 해양사고 예방&lt;/p&gt;&lt;p&gt;교육 대상 : 선장 및 선장 진급 예정자&lt;/p&gt;&lt;p&gt;교육 시간 :  1일, 6시간 (수료증 유효기간 : 3년)&lt;/p&gt;&lt;p&gt;교육 일정 : 매달 1회 실시(30명/회)&lt;/p&gt;&lt;p&gt;교육 혜택 : 수료자 대상 인센티브 제공&lt;/p&gt;&lt;p&gt;&lt;br&gt;&lt;/p&gt;&lt;p&gt;* 자세한 일정은 공지사항 참조&lt;/p&gt;','Y',0),(18,'2024년도 항내운항안전교육','CS','서울/부산',1,24,7,6,3,400000,'','&lt;p&gt;교육 개요&lt;/p&gt;&lt;p&gt;&lt;br&gt;&lt;/p&gt;&lt;p&gt;교육목적 : 항내 선박조종 이론 습득 및 해양사고 예방&lt;/p&gt;&lt;p&gt;교육대상 : 선장 및 선장진급 예정자&lt;/p&gt;&lt;p&gt;교육시간 : 1일, 6시간(수료증 유효기간 : 3년)&lt;/p&gt;&lt;p&gt;교육일정 : 매달 1회 실시(30명/회)&lt;/p&gt;&lt;p&gt;&lt;br&gt;&lt;/p&gt;&lt;p&gt;&lt;br&gt;&lt;/p&gt;&lt;p&gt;* 자세한 일정은 공지사항 참조&lt;/p&gt;','C',1),(19,'2025년도 항내운항안전교육','CS','서울/부산',1,25,7,6,3,500000,'','&lt;p style=&#34letter-spacing: -0.2px;&#34&gt;교육 개요&lt;/p&gt;&lt;p style=&#34letter-spacing: -0.2px;&#34&gt;&lt;br&gt;&lt;/p&gt;&lt;p style=&#34letter-spacing: -0.2px;&#34&gt;교육목적 : 항내 선박조종 이론 습득 및 해양사고 예방&lt;/p&gt;&lt;p style=&#34letter-spacing: -0.2px;&#34&gt;교육대상 : 선장 및 선장진급 예정자&lt;/p&gt;&lt;p style=&#34letter-spacing: -0.2px;&#34&gt;교육시간 : 1일, 6시간(수료증 유효기간 : 3년)&lt;/p&gt;&lt;p style=&#34letter-spacing: -0.2px;&#34&gt;교육일정 : 매달 1회 실시(25명/회)&lt;/p&gt;&lt;p style=&#34letter-spacing: -0.2px;&#34&gt;&lt;br&gt;&lt;/p&gt;&lt;p style=&#34letter-spacing: -0.2px;&#34&gt;&lt;br&gt;&lt;/p&gt;&lt;p style=&#34letter-spacing: -0.2px;&#34&gt;* 자세한 일정은 공지사항 참조&lt;/p&gt;','Y',2),(20,'2025년도 해운선사 선박운항 체험교육','SE','서울',1,5,5,2,0,0,'','&lt;p style=&#34letter-spacing: -0.2px;&#34&gt;교육 개요&lt;/p&gt;&lt;p style=&#34letter-spacing: -0.2px;&#34&gt;&lt;br&gt;&lt;/p&gt;&lt;p style=&#34letter-spacing: -0.2px;&#34&gt;교육목적 : 선박조종 시뮬레이션을 활용한 승선 체험 기회를 제공하여, 해운 실무에 대한 입체적 이해를 증진&lt;/p&gt;&lt;p style=&#34letter-spacing: -0.2px;&#34&gt;교육대상 : 비승선 해운선사 임직원&lt;/p&gt;&lt;p style=&#34letter-spacing: -0.2px;&#34&