  `memo` text COMMENT '비고',
  `message` text COMMENT '문자발송메세지',
  `schedule_index` tinyint(3) unsigned DEFAULT NULL COMMENT '차수',
  PRIMARY KEY (`idx`)
) ENGINE=InnoDB AUTO_INCREMENT=10 DEFAULT CHARSET=utf8;
