DROP TABLE IF EXISTS `tbl_email_log`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `tbl_email_log` (
  `idx` int(10) unsigned NOT NULL AUTO_INCREMENT COMMENT '키값',
  `code` varchar(20) NOT NULL COMMENT '발송메일 키값',
  `title` varchar(200) NOT NULL COMMENT '메일제목',
  `content` text NOT NULL COMMENT '메일내용',
  `tomail` varchar(100) NOT NULL COMMENT '받는 이메일',
  `regdate` datetime NOT NULL COMMENT '등록일시',
  PRIMARY KEY (`idx`)
) ENGINE=InnoDB AUTO_INCREMENT=61 DEFAULT CHARSET=utf8 COMMENT='단체메일 로그';
/*!40101 SET character_set_client = @saved_cs_client */;

