INSERT INTO `tbl_email_log` VALUES (1,'','회원가입을 환영합니다.','&lt;div id=&#34mailing_wrap&#34 style=&#34margin: 0px auto; border: 20px solid rgb(242, 242, 242); border-image: none; width: 770px; box-sizing: border-box; background-color: rgb(242, 242, 242);&#34&gt;\r\n		&lt;header style=&#34height: 126px; overflow: hidden; border-bottom-color: rgb(204, 204, 204); border-bottom-width: 1px; border-bottom-style: solid; background-color: rgb(255, 255, 255);&#34&gt;\r\n			&lt;h1 style=&#34margin: 0px; padding: 0px;&#34&gt;&lt;a style=&#34margin: 0px; padding: 0px;&#34 href=&#34https://kopec1.cafe24.com&#34&gt;&lt;img style=&#34margin: 30px; line-height: 126px; vertical-align: middle; float: left;&#34 alt=&#34&#34 src=&#34https://kopec1.cafe24.com/data/home/20221210201225.png&#34&gt;&lt;/a&gt;&lt;/h1&gt;\r\n			&lt;h2 style=&#34margin: 0px 30px 0px 0px; padding: 0px; color: rgb(51, 51, 51); line-height: 126px; font-size: 24px; font-weight: 400; float: right;&#34&gt;회원가입 안내메일&lt;/h2&gt;\r\n		&lt;/header&gt;\r\n		&lt;section class=&#34mailing_container&#34 style=&#34padding: 40px 0px 70px; text-align: center; box-sizing: border-box; background-color: rgb(255, 255, 255);&#34&gt;&lt;h3 style=&#34margin: 15px 0px; padding: 30px 0px 0px;&#34&gt;&lt;font color=&#34#2985db&#34&gt;&lt;span style=&#34font-size: 26px;&#34&gt;한국도선안전교육센터&lt;/span&gt;&lt;/font&gt;&lt;span style=&#34font-size: 26px;&#34&gt;에 가입하신 것을 환영합니다!&lt;/span&gt;&lt;/h3&gt;\r\n			&lt;p style=&#34margin: 0px; padding: 0px; line-height: 24px; font-size: 14px;&#34&gt;안녕하세요. &lt;span style=&#34font-weight: bold;&#34&gt;테스트담당자&lt;/span&gt; 고객님!&lt;/p&gt;\r\n			&lt;p style=&#34margin: 0px; padding: 0px; line-height: 24px; font-size: 14px;&#34&gt;고객님의 회원가입이 완료되었으며,한국도선안전교육센터가족이 되신 것을 진심으로 환영합니다.&lt;/p&gt;\r\n			&lt;p style=&#34margin: 0px; padding: 0px; line-height: 24px; font-size: 14px;&#34&gt;앞으로도 고객님을 위해 최선을 다하는 한국도선안전교육센터(이)가 되도록 노력하겠습니다.&lt;/p&gt;\r\n		&lt;/section&gt;\r\n		&lt;section class=&#34mailing_container2&#34 style=&#34margin: 30px 0px 0px; padding: 30px 0px 30px 43px; background-color: rgb(255, 255, 255);&#34&gt;\r\n			&lt;p style=&#34text-align: left; line-height: 22px; letter-spacing: -1px; font-size: 13px; font-weight: 300;&#34&gt;\r\n				본 메일은 발신전용 메일이며 문의에 대한 회신 처리되지 않습니다. 문의사항은 고객센터를 이용해주세요.&lt;br&gt;\r\n				회원이 아니신 경우나 메일 수신거부 회원이신데도 메일을 받으신다면 &lt;a style=&#34color: rgb(51, 51, 51); letter-spacing: -0.5px; font-size: 12px; background-color: rgb(242, 242, 242); text-decoration-line: none;&#34 href=&#34mailto:kopec@kmpilot.or.kr&#34&gt;kopec@kmpilot.or.kr&lt;/a&gt; 으로 연락해 주세요.\r\n			&lt;/p&gt;\r\n		&lt;/section&gt;\r\n		&lt;div class=&#34mailing_footer&#34 id=&#34footer&#34 style=&#34margin-top: 40px;&#34&gt;\r\n			&lt;div class=&#34footer_bot&#34 style=&#34height: 120px; background-color: rgb(242, 242, 242);&#34&gt;\r\n				&lt;div class=&#34wrap_layout&#34 style=&#34padding: 0px 43px; width: 100%; box-sizing: border-box;&#34&gt;\r\n					&lt;div class=&#34f_content&#34 style=&#34float: left;&#34&gt;\r\n						&lt;address style=&#34line-height: 22px; display: block;&#34&gt;&lt;address style=&#34color: rgb(149, 149, 149); line-height: 22px; letter-spacing: -0.5px; font-style: normal; font-weight: 300;&#34&gt;&lt;address style=&#34line-height: 22px; font-style: normal;&#34&gt;&lt;span class=&#34bar&#34&gt;한국도선안전교육센터 |&lt;/span&gt; 서울 서초구 반포대로 94 (서초동) 5층 | &lt;span class=&#34bar&#34&gt; &lt;/span&gt;대표 윤호섭, 여명준            &lt;/address&gt;&lt;p style=&#34line-height: 22px;&#34&gt;사업자등록번호 받아야함  &lt;span class=&#34bar&#34&gt;|&lt;/span&gt;   통신판매업신고  &lt;/p&gt;&lt;p style=&#34line-height: 22px;&#34&gt;고객센터 02-780-8042 &lt;span class=&#34bar&#34&gt;|&lt;/span&gt;  이메일 : &lt;a style=&#34color: rgb(51, 51, 51); text-decoration-line: none;&#34 href=&#34mailto:kopec@kmpilot.or.kr&#34&gt;kopec@kmpilot.or.kr&lt;/a&gt;&lt;/p&gt;&lt;br style=&#34color: rgb(0, 0, 0); letter-spacing: normal; font-style: italic;&#34&gt;&lt;p class=&#34copy&#34 style=&#34color: rgb(0, 0, 0); line-height: