  `m_idx` int(10) unsigned NOT NULL AUTO_INCREMENT COMMENT '키값',
  `shop_name` varchar(50) NOT NULL COMMENT '지점명',
  `zip` varchar(5) NOT NULL COMMENT '우편번호',
  `addr1` varchar(50) NOT NULL COMMENT '기본주소',
  `addr2` varchar(100) NOT NULL COMMENT '상세주소',
  `phone` varchar(50) NOT NULL COMMENT '연락처',
  `email` varchar(100) NOT NULL COMMENT '메일주소',
  `regdate` datetime NOT NULL COMMENT '등록일',
  `status` char(1) NOT NULL COMMENT '상태값 Y:사용 N:미사용 ',
  PRIMARY KEY (`m_idx`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='매장정보';
