--
-- Table structure for table `tbl_member`
--

DROP TABLE IF EXISTS `tbl_member`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `tbl_member` (
  `m_idx` int(10) unsigned NOT NULL AUTO_INCREMENT COMMENT '키값 ',
  `user_id` varchar(200) NOT NULL COMMENT '회원아이디 ',
  `user_pw` varchar(300) NOT NULL COMMENT '회원 패스워드 ',
  `user_name` varchar(100) NOT NULL COMMENT '회원 이름 ',
  `sms_yn` varchar(1) DEFAULT NULL COMMENT '문자 수신여부 ',
  `user_phone` varchar(50) DEFAULT NULL COMMENT '고객 전화번호 ',
  `user_mobile` varchar(50) NOT NULL COMMENT '고객 휴대폰 ',
  `user_email` varchar(100) NOT NULL COMMENT '회원 이메일 ',
  `user_email_yn` varchar(1) DEFAULT NULL COMMENT '이메일 수신여부 ',
  `user_level` tinyint(4) NOT NULL COMMENT '1:관리자 9:일반사용자 8:타등급 ',
  `zip` varchar(7) DEFAULT NULL COMMENT '우편번호 ',
  `addr1` varchar(200) DEFAULT NULL COMMENT '기본주소 ',
  `addr2` varchar(200) DEFAULT NULL COMMENT '상세주소 ',
  `status` varchar(1) NOT NULL COMMENT '상태값 0:삭제, 1:정상 2:정지',
  `user_ip` varchar(20) NOT NULL COMMENT '고객 아이피 ',
  `login_date` datetime DEFAULT NULL COMMENT '로그인 시각 ',
  `r_date` datetime NOT NULL COMMENT '등록일시 ',
  `birthday_type` int(11) DEFAULT NULL COMMENT '0:양력 1: 음력',
  `account_name` varchar(100) DEFAULT NULL COMMENT '예금주',
  `bank` varchar(5) DEFAULT NULL COMMENT '은행코드',
  `account_num` varchar(20) DEFAULT NULL COMMENT '계좌번호',
  `login_count` bigint(20) unsigned DEFAULT '0' COMMENT '로그인횟수',
  `sns_key` varchar(150) DEFAULT NULL,
  `company_name` varchar(100) DEFAULT NULL COMMENT '법인명',
  `company_representative` varchar(50) DEFAULT NULL COMMENT '대표자',
  `company_code` varchar(50) DEFAULT NULL COMMENT '사업자등록번호',
  `company_file` varchar(300) DEFAULT NULL COMMENT '사업자등록증',
  `work_position` varchar(50) DEFAULT NULL COMMENT '직책',
  `company_mail` varchar(100) DEFAULT NULL COMMENT '업무용 이메일',
  PRIMARY KEY (`m_idx`),
  UNIQUE KEY `uk_id` (`user_id`)
) ENGINE=InnoDB AUTO_INCREMENT=160 DEFAULT CHARSET=utf8 COMMENT='회원테이블 ';
/*!40101 SET character_set_client = @saved_cs_client */;

