CREATE TABLE `tbl_order` (
  `idx` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `order_code` varchar(50) NOT NULL COMMENT '주문코드',
  `status` varchar(20) NOT NULL COMMENT '상태값 config에서 $_deli_type 상태값 참고',
  `user_id` varchar(100) NOT NULL COMMENT '회원아이디',
  `receive_name` varchar(100) NOT NULL COMMENT '받는분',
  `zipcode` varchar(5) NOT NULL COMMENT '우편번호',
  `addr1` varchar(200) NOT NULL COMMENT '기본주소',
  `addr2` varchar(200) NOT NULL COMMENT '상세주소',
  `hp` varchar(20) NOT NULL COMMENT '휴대전화',
  `tel` varchar(20) NOT NULL COMMENT '추가연락처',
  `email` varchar(200) NOT NULL COMMENT '이메일',
  `delivery_way` varchar(300) NOT NULL COMMENT '배송방법',
  `deli_content` varchar(300) NOT NULL,
  `usecash` varchar(20) NOT NULL COMMENT '사용캐쉬',
  `coupon` int(11) NOT NULL COMMENT '사용쿠폰',
  `total_price` varchar(20) NOT NULL COMMENT '결제금액',
  `addcash` varchar(20) NOT NULL COMMENT '적립캐쉬',
  `cash_date` varchar(30) NOT NULL COMMENT '결제일자',
  `regdate` datetime NOT NULL COMMENT '등록일자',
  `tid` varchar(100) NOT NULL COMMENT '거래번호',
  `payMethod` varchar(20) NOT NULL COMMENT '결제방법',
  `moid` varchar(100) NOT NULL COMMENT '주문 번호',
  `applDate` varchar(20) NOT NULL COMMENT '승인날짜',
  `applTime` varchar(20) NOT NULL COMMENT '승인시간',
  `payText` varchar(200) NOT NULL COMMENT '결제텍스트',
  `memo` text NOT NULL COMMENT '메모',
  `invo_corp` int(10) unsigned NOT NULL COMMENT '택배사',
  `invoice` varchar(200) NOT NULL COMMENT '송장번호',
  `complete_date` datetime NOT NULL COMMENT '배송완료일',
  `return_date` datetime NOT NULL COMMENT '반품접수일',
  `pay_device` char(1) NOT NULL COMMENT '결제기기 P:pc M:mobile',
  `delivery_price` varchar(20) NOT NULL COMMENT '배송비',
  `pg_del` char(1) NOT NULL COMMENT 'pg사 결제 취소',
  `invo_corp2` int(11) NOT NULL COMMENT '반품 택배사',
  `invoice2` varchar(200) NOT NULL COMMENT '반품 송장번호',
  `invoice3` varchar(200) DEFAULT NULL,
  `content_p` text COMMENT '교환사유',
  `content_o` text COMMENT '반품사유',
  `kcb_di` varchar(100) DEFAULT NULL COMMENT 'KCB 구입 확인',
  PRIMARY KEY (`idx`)
) ENGINE=InnoDB AUTO_INCREMENT=279 DEFAULT CHARSET=utf8 COMMENT='주문테이블';
