--
-- Table structure for table `tbl_pass_list2`
--

DROP TABLE IF EXISTS `tbl_pass_list2`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `tbl_pass_list2` (
  `idx` int(11) NOT NULL AUTO_INCREMENT,
  `reservation_idx` int(11) DEFAULT NULL COMMENT 'tbl_reservation idx',
  `m_idx` int(11) DEFAULT NULL COMMENT '유저ID 고유값',
  `certificate_code` varchar(30) DEFAULT NULL COMMENT '증서코드',
  `company_code` varchar(50) DEFAULT NULL COMMENT '사업자등록번호',
  `company_name` varchar(200) DEFAULT NULL COMMENT '법인명',
  `sub_company_name` varchar(200) DEFAULT NULL COMMENT '소속선사',
  `education_subject` varchar(100) NOT NULL COMMENT '교육과정명',
  `position` varchar(30) DEFAULT NULL COMMENT '직급',
  `name` varchar(30) DEFAULT NULL COMMENT '이름',
  `gender` char(1) DEFAULT NULL COMMENT '성별',
  `birthday` date NOT NULL DEFAULT '0000-00-00' COMMENT '생년월일',
  `age` int(2) DEFAULT NULL COMMENT '나이',
  `phone` varchar(15) DEFAULT NULL COMMENT '휴대폰번호',
  `residence` varchar(15) DEFAULT NULL COMMENT '거주지',
  `schedule_start` date NOT NULL DEFAULT '0000-00-00' COMMENT '교육일정 시작',
  `schedule_end` date NOT NULL DEFAULT '0000-00-00' COMMENT '교육일정 종료',
  `education_time` double DEFAULT NULL COMMENT '교육시간',
  `expiration_period` date NOT NULL DEFAULT '0000-00-00' COMMENT '유효기간',
  `r_date` datetime NOT NULL DEFAULT '0000-00-00 00:00:00' COMMENT '수료일자',
  `harbor` varchar(100) DEFAULT NULL,
  `first_date` varchar(20) DEFAULT NULL,
  `end_date` varchar(20) DEFAULT NULL,
  `codes` varchar(20) DEFAULT NULL,
  PRIMARY KEY (`idx`)
) ENGINE=InnoDB AUTO_INCREMENT=38 DEFAULT CHARSET=utf8;
/*!40101 SET character_set_client = @saved_cs_client */;

