DROP TABLE IF EXISTS `tbl_point_del`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `tbl_point_del` (
  `idx` int(10) unsigned NOT NULL COMMENT '키값',
  `user_id` varchar(30) NOT NULL COMMENT '회원아이디',
  `o_idx` int(10) unsigned NOT NULL DEFAULT '0' COMMENT '주문키값',
  `msg` varchar(200) NOT NULL COMMENT '내용',
  `point` varchar(11) NOT NULL COMMENT '지급포인트',
  `regdate` datetime NOT NULL,
  `enddate` date NOT NULL COMMENT '소멸일자',
  PRIMARY KEY (`idx`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='삭제포인트';
/*!40101 SET character_set_client = @saved_cs_client */;

