DROP TABLE IF EXISTS `tbl_policy`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `tbl_policy` (
  `p_idx` int(10) unsigned NOT NULL AUTO_INCREMENT COMMENT '키값 ',
  `members` text NOT NULL COMMENT '회원약관 ',
  `minfo1` text NOT NULL COMMENT '수집하는 개인정보의 항목 ',
  `minfo2` text NOT NULL COMMENT '개인정보의 수집이용 목적 ',
  `minfo3` text NOT NULL COMMENT '개인정보의 보유 및 이용시간',
  `trans` text NOT NULL COMMENT '배송/교환/반품/취소',
  `emails` text NOT NULL,
  PRIMARY KEY (`p_idx`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8 COMMENT='약관 및 정책 ';
/*!40101 SET character_set_client = @saved_cs_client */;

