CREATE TABLE `tbl_popup` (
  `idx` int(11) NOT NULL AUTO_INCREMENT,
  `P_SUBJECT` varchar(200) NOT NULL DEFAULT '' COMMENT '팝업제목',
  `P_STARTDAY` varchar(10) NOT NULL DEFAULT '' COMMENT '시작날짜',
  `P_START_HH` varchar(2) NOT NULL DEFAULT '' COMMENT '시작시간',
  `P_START_MM` varchar(2) NOT NULL DEFAULT '' COMMENT '시작월',
  `P_ENDDAY` varchar(10) NOT NULL DEFAULT '' COMMENT '종료날',
  `P_END_HH` varchar(2) NOT NULL DEFAULT '' COMMENT '종료시간',
  `P_END_MM` varchar(2) NOT NULL DEFAULT '' COMMENT '종료분',
  `P_POPUP_U` char(1) NOT NULL DEFAULT '' COMMENT '팝업현황',
  `P_MOVEURL` varchar(255) NOT NULL DEFAULT '' COMMENT '연결URL',
  `P_WIN_WIDTH` int(11) NOT NULL DEFAULT '0' COMMENT '팝업넓이',
  `P_WIN_LEFT` int(11) NOT NULL DEFAULT '0' COMMENT '팝업좌측위치',
  `P_CATE` char(1) NOT NULL DEFAULT '' COMMENT '노출방식/L:레이어, W:윈도우',
  `P_STYLE` char(1) NOT NULL DEFAULT '' COMMENT '모바일여부',
  `P_CONTENT` text NOT NULL COMMENT '내용',
  `ufile` varchar(50) NOT NULL DEFAULT '' COMMENT '모바일용 업로드된 파일명',
  `rfile` varchar(50) NOT NULL DEFAULT '' COMMENT '모바일용 실제파일명',
  `status` char(1) NOT NULL DEFAULT '' COMMENT '노출여부',
  `is_mobile` char(1) NOT NULL DEFAULT '' COMMENT '모바일사용여부',
  `r_date` datetime NOT NULL DEFAULT '0000-00-00 00:00:00' COMMENT '등록일',
  `P_WIN_TOP` int(11) NOT NULL DEFAULT '0' COMMENT '팝업 탑 위치',
  `P_WIN_HEIGHT` int(11) NOT NULL DEFAULT '0' COMMENT '팝업높이',
  PRIMARY KEY (`idx`)
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8;
/*!40101 SET character_set_client = @saved_cs_client */;

