--
-- Table structure for table `tbl_reservation3`
--

DROP TABLE IF EXISTS `tbl_reservation3`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `tbl_reservation3` (
  `idx` int(11) NOT NULL AUTO_INCREMENT,
  `m_idx` int(11) DEFAULT NULL COMMENT '유저ID 고유값',
  `education_idx` int(11) DEFAULT NULL COMMENT 'tbl_education idx',
  `schedule_idx` int(11) DEFAULT NULL COMMENT 'tbl_education_schedule idx',
  `company_code` varchar(50) DEFAULT NULL COMMENT '사업자등록번호',
  `company_name` varchar(200) DEFAULT NULL COMMENT '법인명',
  `sub_company_name` varchar(200) DEFAULT NULL COMMENT '소속선사',
  `position` varchar(30) DEFAULT NULL COMMENT '직급',
  `name` varchar(30) DEFAULT NULL COMMENT '이름',
  `gender` char(1) DEFAULT NULL COMMENT '성별',
  `birthday` date NOT NULL DEFAULT '0000-00-00' COMMENT '생년월일',
  `phone` varchar(15) DEFAULT NULL COMMENT '휴대폰번호',
  `residence` varchar(15) DEFAULT NULL COMMENT '거주지',
  `type` int(1) DEFAULT NULL COMMENT '예약구분 0=취소, 1=정원, 2=추가',
  `status` char(1) NOT NULL DEFAULT 'N' COMMENT '입금상태 Y=입금확인, N=입금대기, C=입금취소',
  `pass` char(1) NOT NULL DEFAULT 'N' COMMENT '이수 상태',
  `sms_status` char(1) NOT NULL DEFAULT 'N' COMMENT '문자 발송상태',
  `r_date` datetime NOT NULL DEFAULT '0000-00-00 00:00:00' COMMENT '예약일시',
  `u_date` datetime NOT NULL DEFAULT '0000-00-00 00:00:00' COMMENT '예약수정일시',
  `c_date` datetime NOT NULL DEFAULT '0000-00-00 00:00:00' COMMENT '취소 날짜 및 시간',
  `confirm_date` datetime NOT NULL DEFAULT '0000-00-00 00:00:00' COMMENT '입금 날짜 및 시간',
  `first_date` varchar(20) DEFAULT NULL COMMENT '최초면허 발급일',
  `end_date` varchar(20) DEFAULT NULL COMMENT '면허만료일자',
  `man_date` varchar(20) DEFAULT NULL COMMENT '정년일자',
  `harbor` varchar(100) DEFAULT NULL COMMENT '항구',
  PRIMARY KEY (`idx`)
) ENGINE=InnoDB AUTO_INCREMENT=20 DEFAULT CHARSET=utf8;
/*!40101 SET character_set_client = @saved_cs_client */;

