INSERT INTO `tbl_review` VALUES (7,3,'minke1@uwal.co.kr','고객만족 컨설팅',4,'컨설팅 과정을 통해 높은 학문의 힘을 기르며 원활한 의사소통을 통해\r\n최상의 고객 만족도를위해 항상 노력합니다.','Y','2022-02-24 10:01:10'),(8,2,'minke1@uwal.co.kr','전문적인 학술 컨설팅으로 높은 학문의 힘을 길러드립니다.',5,'정확한 논문컨설팅과 함께 정확한 솔루션을 제시합니다.\r\n\r\n전문적인 솔루션\r\n\r\n정확한 분석으로 여러분의 멘토가 되어 스스로 문제해결 방법을\r\n찾을 수 있도록 구체적인 솔루션을 제시합니다.\r\n\r\n고객만족 컨설팅\r\n\r\n컨설팅 과정을 통해 높은 학문의 힘을 기르며 원활한 의사소통을 통해\r\n최상의 고객 만족도를위해 항상 노력합니다.','Y','2022-02-25 01:05:17');
/*!40000 ALTER TABLE `tbl_review` ENABLE KEYS */;
UNLOCK TABLES;

